#include <bits/stdc++.h>
using namespace std;
struct number{
    int val,pos;
}a[8100];
int n,q;
int ans[8100];
bool operator < (number a,number b){
    return (a.val<b.val) || (a.val==b.val && a.pos<b.pos);
}
int main(){
    cin>>n>>q;
    for(int i=1;i<=n;i++){
        cin>>a[i].val;
        a[i].pos=i;
    }
    for(int i=1;i<=n;i++){
        for(int j=i+1;j<=n;j++)
            if(a[j]<a[i])swap(a[j],a[i]);
    }
    for(int i=1;i<=n;i++){
        ans[a[i].pos]=i;
    }
    for(int i=0;i<q;i++){
        int op;
        cin>>op;
        if(op==2){
            int x;
            cin>>x;
            cout<<ans[x]<<endl;
        }
        else{
            int x,v;
            cin>>x>>v;
            int p=ans[x];
            a[p].val=v;
            number tmp=a[p];
            for(int j=p;j<n;j++){
                a[j]=a[j+1];
            }
            a[n]=tmp;
            for(int j=n;j>=2;j--){
                if(a[j]<a[j-1])swap(a[j],a[j-1]);
                else break;
            }
            for(int j=1;j<=n;j++)
                ans[a[j].pos]=j;
        }
    }
    return 0;    
}
